  1	import * as React from 'react';
  2	import { VolumeSnapshotClassKind, VolumeSnapshotClassModel } from '@odf/shared';
  3	import { SingleSelectDropdown } from '@odf/shared/dropdown';
  4	import { getName } from '@odf/shared/selectors';
  5	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  6	import { getValidWatchK8sResourceObj } from '@odf/shared/utils';
  7	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
  8	import {
  9	  Alert,
 10	  Checkbox,
 11	  FormGroup,
 12	  FormHelperText,
 13	  HelperText,
 14	  HelperTextItem,
 15	  NumberInput,
 16	  Radio,
 17	  SelectOption,
 18	} from '@patternfly/react-core';
 19	import { QuestionCircleIcon } from '@patternfly/react-icons';
 20	import { WizardDispatch, WizardState } from '../../../reducer';
 21	
 22	enum CronTime {
 23	  DAILY = 'daily',
 24	  WEEKLY = 'weekly',
 25	  MONTHLY = 'monthly',
 26	}
 27	
 28	const CRON_MAP: Record<CronTime, string> = {
 29	  [CronTime.DAILY]: '0 0 * * *', // Every day at 12:00 AM
 30	  [CronTime.WEEKLY]: '0 0 * * 6', // Every Saturday at 12:00 AM
 31	  [CronTime.MONTHLY]: '0 0 1-7 * 6', // First Saturday of each month at 12:00 AM
 32	};
 33	
 34	const getCronTimeFromSchedule = (schedule: string): CronTime => {
 35	  const entry = Object.entries(CRON_MAP).find(
 36	    ([, value]) => value === schedule
 37	  );
 38	  return entry ? (entry[0] as CronTime) : CronTime.DAILY;
 39	};
 40	
 41	const selectOptions = (volumeSnapshotClasses: VolumeSnapshotClassKind[]) =>
 42	  volumeSnapshotClasses?.map((vsc) => (
 43	    <SelectOption
 44	      key={vsc.metadata.uid}
 45	      value={vsc.metadata.name}
 46	      data-test-id={vsc.metadata.name}
 47	    >
 48	      {getName(vsc)}
 49	    </SelectOption>
 50	  )) || [];
 51	
 52	type AutomaticBackupProps = {
 53	  dispatch: WizardDispatch;
 54	  isDbBackup: boolean;
 55	  isMCG: boolean;
 56	  isExternalPostgresEnabled: boolean;
 57	  dbBackup: WizardState['advancedSettings']['dbBackup'];
 58	};
 59	
 60	export const AutomaticBackup: React.FC<AutomaticBackupProps> = ({
 61	  dispatch,
 62	  isDbBackup,
 63	  isMCG,
 64	  dbBackup,
 65	  isExternalPostgresEnabled,
 66	}) => {
 67	  const { t } = useCustomTranslation();
 68	  const { schedule, volumeSnapshot } = dbBackup;
 69	  const [volumeSnapshotClasses, vscLoaded] = useK8sWatchResource<
 70	    VolumeSnapshotClassKind[]
 71	  >(
 72	    getValidWatchK8sResourceObj(
 73	      {
 74	        groupVersionKind: {
 75	          group: VolumeSnapshotClassModel.apiGroup,
 76	          version: VolumeSnapshotClassModel.apiVersion,
 77	          kind: VolumeSnapshotClassModel.kind,
 78	        },
 79	        isList: true,
 80	      },
 81	      isMCG
 82	    )
 83	  );
 84	
 85	  const selectedFrequency = getCronTimeFromSchedule(schedule);
 86	  const handleSelect = (type: CronTime) => {
 87	    dispatch({
 88	      type: 'advancedSettings/dbBackup/schedule',
 89	      payload: CRON_MAP[type],
 90	    });
 91	  };
 92	
 93	  const onVolumeSnapshotChange = (vscName: string) => {
 94	    dispatch({
 95	      type: 'advancedSettings/dbBackup/volumeSnapshot/volumeSnapshotClass',
 96	      payload: vscName,
 97	    });
 98	  };
 99	
100	  const onBackupCopiesChange = (
101	    funcType: 'onChange' | 'onMinus' | 'onPlus',
102	    event?: React.FormEvent<HTMLInputElement>
103	  ) => {
104	    let newValue: number;
105	    switch (funcType) {
106	      case 'onChange': {
107	        const value = (event.target as HTMLInputElement).value;
108	        const numValue = parseInt(value, 10);
109	        newValue = isNaN(numValue)
110	          ? 0
111	          : Math.max(1, Math.min(numValue || 1, 12));
112	        break;
113	      }
114	      case 'onMinus': {
115	        newValue = Math.max(volumeSnapshot.maxSnapshots - 1, 1);
116	        break;
117	      }
118	      case 'onPlus': {
119	        newValue = Math.min(volumeSnapshot.maxSnapshots + 1, 12);
120	        break;
121	      }
122	    }
123	    dispatch({
124	      type: 'advancedSettings/dbBackup/volumeSnapshot/maxSnapshots',
125	      payload: newValue,
126	    });
127	  };
128	
129	  return (
130	    <>
131	      <Checkbox
132	        id="automatic-backup"
133	        label={t('Automatic backup')}
134	        description={t(
135	          'Opt in for automatic backup for MultiCloud Object Gateway metadata database'
136	        )}
137	        isChecked={isDbBackup}
138	        isDisabled={!vscLoaded || isExternalPostgresEnabled}
139	        onChange={() =>
140	          dispatch({
141	            type: 'advancedSettings/setDbBackup',
142	            payload: !isDbBackup,
143	          })
144	        }
145	        className="odf-advanced-settings__checkbox"
146	      />
147	      {!vscLoaded && (
148	        <Alert
149	          variant="info"
150	          title={t('No volume snapshot class present')}
151	          isInline
152	          className="pf-v6-u-mt-sm"
153	        >
154	          {t(
155	            'VolumeSnapshotClass is required to use this feature. Ensure a VolumeSnapshotClass is present in the cluster.'
156	          )}
157	        </Alert>
158	      )}
159	      {isDbBackup && (
160	        <>
161	          <FormGroup
162	            role="radiogroup"
163	            fieldId="backup-frequency-radio-group"
164	            label={t('Backup frequency')}
165	            labelHelp={<QuestionCircleIcon />}
166	            className="pf-v6-u-mt-md"
167	            isRequired
168	          >
169	            <Radio
170	              name="backup-frequency"
171	              label={t('Daily')}
172	              id="backup-frequency-daily"
173	              description={t('Backup occurs at 12:00 AM every day')}
174	              isChecked={selectedFrequency === CronTime.DAILY}
175	              onChange={() => handleSelect(CronTime.DAILY)}
176	              className="pf-v6-u-p-sm"
177	            />
178	            <Radio
179	              name="backup-frequency"
180	              label={t('Weekly')}
181	              id="backup-frequency-weekly"
182	              description={t('Backup occurs at 12:00 AM every Saturday')}
183	              isChecked={selectedFrequency === CronTime.WEEKLY}
184	              onChange={() => handleSelect(CronTime.WEEKLY)}
185	              className="pf-v6-u-p-sm"
186	            />
187	            <Radio
188	              name="backup-frequency"
189	              label={t('Monthly')}
190	              id="backup-frequency-monthly"
191	              description={t(
192	                'Backup occurs at 12:00 AM on the first Saturday of each month'
193	              )}
194	              isChecked={selectedFrequency === CronTime.MONTHLY}
195	              onChange={() => handleSelect(CronTime.MONTHLY)}
196	              className="pf-v6-u-p-sm"
197	            />
198	          </FormGroup>
199	          <FormGroup
200	            fieldId="backup-copies"
201	            label={t('Number of backup copies to be retained')}
202	            className="pf-v6-u-mb-sm"
203	            isRequired
204	          >
205	            <NumberInput
206	              id="backup-copies-input"
207	              value={volumeSnapshot.maxSnapshots}
208	              min={1}
209	              max={12}
210	              onMinus={() => onBackupCopiesChange('onMinus')}
211	              onPlus={() => onBackupCopiesChange('onPlus')}
212	              onChange={(event) => onBackupCopiesChange('onChange', event)}
213	              minusBtnAriaLabel={t('Decrement')}
214	              plusBtnAriaLabel={t('Increment')}
215	            />
216	            <FormHelperText>
217	              <HelperText>
218	                <HelperTextItem>
219	                  {t('Number of backups can be between 1-12')}
220	                </HelperTextItem>
221	              </HelperText>
222	            </FormHelperText>
223	          </FormGroup>
224	          {isMCG && (
225	            <FormGroup
226	              fieldId="backup-add-volumeSnapshotClass"
227	              label={t('Add VolumeSnapshotClass')}
228	              className="pf-v6-u-mt-md"
229	              isRequired
230	            >
231	              <SingleSelectDropdown
232	                id="volume-snapshot-class-dropdown"
233	                className="pf-v6-u-w-50 pf-v6-u-mt-sm"
234	                selectedKey={volumeSnapshot.volumeSnapshotClass}
235	                selectOptions={selectOptions(volumeSnapshotClasses)}
236	                onChange={onVolumeSnapshotChange}
237	                placeholderText={t('Select a VolumeSnapshotClass')}
238	              />
239	            </FormGroup>
240	          )}
241	        </>
242	      )}
243	    </>
244	  );
245	};

